SELECT 
FROM operation_logs ol
WHERE 1 = 1

    AND ol.username LIKE CONCAT('%', #{username}, '%')


    AND ol.action = #{action}


    AND ol.resource = #{resource}


    AND ol.operated_at >= #{startDate}


    AND ol.operated_at <= CONCAT(#{endDate}, ' 23:59:59')

ORDER BY ol.operated_at DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM operation_logs ol
WHERE 1 = 1

    AND ol.username LIKE CONCAT('%', #{username}, '%')


    AND ol.action = #{action}


    AND ol.resource = #{resource}


    AND ol.operated_at >= #{startDate}


    AND ol.operated_at <= CONCAT(#{endDate}, ' 23:59:59')
